import React, { useEffect, useState } from "react";
import "../styles/MoodTracker.css";

const MoodTracker = () => {
  const [moods, setMoods] = useState([]);

  useEffect(() => {
    // Read moods saved from chat or elsewhere
    const storedMoods = JSON.parse(localStorage.getItem("moodHistory")) || [];
    setMoods(storedMoods);
  }, []);

  return (
    <div className="mood-container">
      <h1 className="mood-title">🧠 Mood Tracker</h1>

      {moods.length === 0 ? (
        <p className="mood-empty">No moods tracked yet.</p>
      ) : (
        <div className="mood-list">
          {moods.map((item, index) => (
            <div key={index} className="mood-card">
              <h3>{item.mood}</h3>
              <p>Intensity: {item.intensity}</p>
              <p className="mood-time">
                {new Date(item.time).toLocaleString()}
              </p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default MoodTracker;
